import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

describe('formatDate', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it('should handle happy path with valid ISO string', () => {
    const isoString = '2024-01-15T10:30:00.000Z';
    const result = formatDate(isoString);
    expect(result).toBe('January 15, 2024');
  });

  it('should handle edge case with different timezone offset', () => {
    const isoString = '2024-12-31T23:59:59.000+05:30';
    const result = formatDate(isoString);
    expect(result).toBe('December 31, 2024');
  });

  it('should handle null/empty input values', () => {
    expect(formatDate(null as any)).toBe('');
    expect(formatDate(undefined as any)).toBe('');
    expect(formatDate('')).toBe('');
    expect(formatDate(0 as any)).toBe('');
  });
});

