import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { truncateContent } from './truncateContent';

describe('truncateContent', () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('should handle happy path by returning content trimmed to the specified maxLength', () => {
    const content = 'Lorem ipsum dolor sit amet, consectetur adipiscing elit.';
    const maxLength = 20;
    const result = truncateContent(content, maxLength);
    expect(result).toBe(content.slice(0, maxLength));
  });

  it('should handle edge case when content length equals maxLength', () => {
    const content = 'ExactLengthString';
    const maxLength = content.length;
    const result = truncateContent(content, maxLength);
    expect(result).toBe(content);
  });

  it('should handle null/empty inputs gracefully', () => {
    // null input
    // @ts-expect-error testing runtime behavior with null
    expect(truncateContent(null, 10)).toBe('');
    // undefined input
    // @ts-expect-error testing runtime behavior with undefined
    expect(truncateContent(undefined, 10)).toBe('');
    // empty string
    expect(truncateContent('', 10)).toBe('');
    // zero maxLength
    const content = 'NonEmpty';
    expect(truncateContent(content, 0)).toBe('');
  });
});

