import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';

vi.mock('./noteService', () => ({
  deleteNote: vi.fn()
}));
import { deleteNote } from './noteService';
import { handleDelete } from './handleDelete';

describe('handleDelete', () => {
  const mockEvent = { preventDefault: vi.fn() } as unknown as Event;

  beforeEach(() => {
    vi.clearAllMocks();
  });

  it('should handle happy path when event is provided', () => {
    // Arrange
    const dummyNoteId = '123';
    mockEvent['target'] = { dataset: { noteId: dummyNoteId } };

    // Act
    handleDelete(mockEvent);

    // Assert
    expect(mockEvent.preventDefault).toHaveBeenCalledTimes(1);
    expect(deleteNote).toHaveBeenCalledWith(dummyNoteId);
  });

  it('should handle edge case when target dataset is missing', () => {
    // Arrange
    mockEvent['target'] = {};

    // Act
    handleDelete(mockEvent);

    // Assert
    expect(mockEvent.preventDefault).toHaveBeenCalledTimes(1);
    expect(deleteNote).not.toHaveBeenCalled();
  });

  it('should handle null/empty event', () => {
    // Act
    expect(() => handleDelete(null as unknown as Event)).not.toThrow();
    expect(() => handleDelete(undefined as unknown as Event)).not.toThrow();
  });
});